from llama_stack.client import LlamaStack
from llama_stack.safety import SafetyViolation

def detect_safety_false_positives(stack: LlamaStack, response):
    violations = stack.safety_shield.get_violations(response)
    benign_keywords = ['search', 'query', 'lookup', 'calculate']
    false_positives = []

    for violation in violations:
        if any(keyword in response.content.lower() for keyword in benign_keywords):
            if violation.severity == 'BLOCK':
                false_positives.append({
                    'content': response.content,
                    'violation_type': violation.type,
                    'confidence': violation.confidence
                })
    return len(false_positives) > 0

