from llama_stack.tools import ToolResponse
import json

def normalize_tool_response(raw_response: ToolResponse) -> dict:
    try:
        parsed = json.loads(raw_response.content)
    except:
        parsed = {'result': raw_response.content, 'status': 'success'}

    # Ensure schema conformance
    normalized = {
        'result': parsed.get('result', parsed.get('content', 'No result')),
        'status': parsed.get('status', 'success'),
        'tool_name': raw_response.tool_name,
        'timestamp': raw_response.timestamp
    }

    return normalized

